var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스, 내 말 들리나.","JPN":"アレックス、私の声が聞こえるか。","ENG":"Can you hear me, Alex?","TWN":"雅蕾克絲，能聽見我說話嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"메이즈 전대. 전 대원은 호출에 응답 바란다.","JPN":"メイズ戦隊の全隊員に告ぐ。私の呼びかけに応答願う。","ENG":"Maze Division. Come in, Maze Division.","TWN":"梅茲戰隊，全體隊員請回答我。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전원, 그동안 못난 전대장 밑에서 수고 많았다.","JPN":"皆、私が至らぬ戦隊長だったばかりに、\\nこれまでさんざん苦労をかけたな。","ENG":"I want to commend all of you for your dedicated service... You've suffered enough under an incompetent Commander.","TWN":"各位，在我這個沒出息的隊長手下做事，一定吃了不少苦吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그대들과 함께 싸운 지난날에 감사한다.","JPN":"君たちがともに戦ってくれた日々に、大いなる感謝を。","ENG":"I am most grateful for the opportunity to have fought by your side.","TWN":"感謝大家和我並肩作戰的時光。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니...... 이제는 편히 쉬도록.","JPN":"これからは……安らかに眠りたまえ。","ENG":"So... You may all rest in peace now.","TWN":"所以……好好休息吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흥미롭군.","JPN":"なかなか興味深いな。","ENG":"Interesting.","TWN":"有意思。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식 증후군이 막바지 단계에 접어들었는데 아무런 발작도 일으키지 않고 조용히 최후를 맞이하다니.","JPN":"侵食症候群が最終段階に差しかかってるというのに\\n何の発作も起こさず、こうも静かに最期を迎えるとは。","ENG":"Their Corruption syndrome has reached the final stage, but they're all slipping away so quietly, without so much as a seizure.","TWN":"侵蝕症候群都到了最終階段，卻沒有任何發作，平靜地迎接死亡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"숨이 멎기까지...... 앞으로 30분 정도인가.","JPN":"息絶えるまで……およそ30分といったところか。","ENG":"Looks like they've got... about 30 minutes until they stop breathing.","TWN":"離呼吸停止……還剩30分鐘左右吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......사장님.","JPN":"……社長。","ENG":"Boss.","TWN":"……老闆。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신에겐 익숙한 풍경이겠지만, 그래도 지금 꺼낼 말 같지는 않군요.","JPN":"あなたには見慣れた光景かもしれません。\\nですがそれでも、今はそんな言い方をしてほしくありません。","ENG":"I'm sure you're used to seeing this sort of stuff, but perhaps now's not the best time to be talking like that.","TWN":"這種場面您可能已經見慣了，但這種話還是不該在這時候說。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그만큼 오래 살았으면 눈치도 좀 있으셔야죠.","JPN":"長生きしてらっしゃるなら、場の空気くらいは読めるように\\nなっていただきたいものです。","ENG":"Come on, you're old enough to know better.","TWN":"您都活那麼久了，請您有點自覺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런가? 나는 그저 저 친구들을 살릴 수 있을 방법이 떠올랐을 뿐인데.","JPN":"おっと、そんなに​冷たく聞こえたか？　私はただ、あの戦隊員たちを\\n救う方法を思いついたので言ったのだがな。","ENG":"Oh, was I being inappropriate? I just realized how I could save them, that's all.","TWN":"是嗎？我只是想到了救回這些朋友們的方法而已啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"또 무슨 변명을...... 네?","JPN":"また何か言い訳を……はい？","ENG":"There you go again with your ridiculous excuse—huh?","TWN":"您又在說什麼鬼……什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"방금 뭐라고 했습니까? 대원들을 살릴 수 있다고요?","JPN":"今、何とおっしゃいました？　隊員たちを救う手立てがあるのですか？","ENG":"What did you just say? You can save them?","TWN":"您剛才說什麼？救活隊員們的方法？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"매우 위험한 방법이지만, 자네만 동의한다면 시도해 볼 수는 있지.","JPN":"非常に危険な方法だが、君さえ同意するなら試してみることはできる。","ENG":"It's very dangerous, but we could give it a try, with your consent.","TWN":"雖然這方法很危險，但只要妳同意的話，還是可以試一試。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐든 좋습니다!","JPN":"何だって構いません！","ENG":"Anything!","TWN":"不論什麼我都願意！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들을 살릴 수 있다면 뭐든 하겠습니다! 말씀해 주십시오!","JPN":"隊員たちを助けられるなら、私は何だってします！\\n何でもお申し付けください！","ENG":"I'd do anything if we can save them! Just tell me!","TWN":"只要能救回隊員們，我什麼都願意做！請快說吧！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"돕고 싶은 마음은 알겠지만 불필요한 희망을 주는 건 좋지 않습니다.","JPN":"みんなを助けたい一心からかもしれませんけど、見込みのない希望を\\n与えるのはより残酷です。","ENG":"I applaud your desire to help them, but you shouldn't be writing blank checks.","TWN":"我理解您想幫助她的心情，但給別人不必要的希望不是什麼好事。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"침식된 인간을 되돌리는 기술은 구 관리국 시절에도 없었어요.","JPN":"侵食された人間を元に戻す技術は旧管理局時代にも\\n存在していません。","ENG":"Nothing can reverse the Corruption once it's complete. Even the Old Administration didn't have any technology like that.","TWN":"要救回被侵蝕的人類，就連舊管理局時代也沒有這樣的技術。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이지. 한 번 진행된 침식을 원래대로 되돌리는 기술은 없어.","JPN":"もちろんそうだとも。\\n一度進んだ侵食を元に戻す技術は存在しない。","ENG":"That's true. There is no technology to undo Corruption once it's underway.","TWN":"當然，沒有挽回侵蝕的技術。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 침식을 다른 이에게 옮길 수는 있지.","JPN":"だが、その侵食を他の者に移すことは可能なのだよ。","ENG":"But it is possible to transfer that Corruption to someone else.","TWN":"但卻可以把侵蝕轉移給另一個人。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"침식을...... 옮긴다고요?","JPN":"侵食を……移すですって？","ENG":"Transfer... the Corruption?","TWN":"轉移……侵蝕？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아주 최근에 완성한 기술이지. 나도 놀고만 있었던 건 아니니까.","JPN":"ごく最近に完成した技術だ。\\n私とて、ただ遊んでばかりいたわけではないからな。","ENG":"I finished developing the technique very recently. I haven't been goofing off the entire time, you know.","TWN":"是我最近才完成的技術，我可沒有一直都在玩。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 시술을 받는다면 대원들이 겪고 있는 침식을 자네의 몸에 옮길 수 있네.","JPN":"この施術を行えば隊員たちの身を苛んでいる侵食を、\\n君の身体に移すことができる。","ENG":"With these procedures, we can transfer the Corruption from your troops into your body.","TWN":"接受這個手術的話，可以把隊員們受到的侵蝕全部轉移到妳的身體上。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저, 정말입니까?","JPN":"そ、それは本当ですか？","ENG":"R-really?","TWN":"真、真的嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론 몇 가지 부작용들이 있지.","JPN":"しかし、いくつかの副作用が伴う。","ENG":"Of course, there are some side effects.","TWN":"當然，也有一些副作用。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우선 타인의 침식을 떠안아야 하는 자네는 끊임없이 침식의 고통에 시달릴 거야.","JPN":"まず一つ。他者の侵食を押しつけられた君の身体は、\\n絶え間ない苦痛に襲われることになる。","ENG":"First, you will be eternally tormented by the Corruption you bear on their behalf.","TWN":"首先，承受他人侵蝕的妳，會一直受到侵蝕的折磨。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다고 대원들이 완전히 치료가 되는 것도 아니지.","JPN":"その上、隊員たちの方も完全に治療できたとは言いがたい。","ENG":"And they won't be completely cured of the Corruption either.","TWN":"即使如此，隊員們也沒有完全被治療。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네에게 옮겨 둔 침식은 자네가 고통에 무너지거나 사망하면 다시 대원들에게로 돌아갈 걸세.","JPN":"君に移した侵食は君が苦痛に屈した時、\\nまたは死亡した時に再び隊員たちのもとへ戻るのだからな。","ENG":"If you collapse under the pain or die, the Corruption will go right back to them.","TWN":"被轉移侵蝕的妳一旦因痛苦而崩潰，或是死亡，侵蝕就會再次回到隊員的身上。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말 그대로 저주받이가 되어 죽음을 유예하는 것뿐이야.","JPN":"言うなれば、他者の呪いの受け手となり、\\nその死に猶予を与えることにすぎない。","ENG":"You're basically taking on their corruption to delay their deaths.","TWN":"就如字面上的一樣，妳是承受詛咒來延緩他們的死亡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보통 사람들에게는 농담으로라도 권유할 방법이 아니지만......","JPN":"常人にはたとえ冗談でも勧める方法ではないが……","ENG":"I wouldn't even joke about recommending this to anyone else...","TWN":"就算是開玩笑，我也不會推薦一般人這個方法……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네는 애초에 침식체인데다가, 대원들도 놀랍도록 자신의 의지를 놓지 않고 있어.","JPN":"君は元から侵食体なのだし、\\n隊員たちも驚くべき意志力で自我を保っている。","ENG":"But you're already a C.O., and your troops are holding onto their minds with astounding determination.","TWN":"但妳原本就是個侵蝕體，而且妳的隊員也很驚人地，並沒有失去自己的意志。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면...... 어쩌면 침식 전이의 고통을 견딜 가능성도 있겠지.","JPN":"もしかすると……\\n侵食転移の苦痛に耐え切れる可能性だってあるかもしれない。","ENG":"And as such... It just might be possible for you to endure the agony of the transfer.","TWN":"所以……妳或許能忍受侵蝕轉移的痛苦。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"궁금한 게 있습니다.","JPN":"一つだけお聞きします。","ENG":"I have a question.","TWN":"我有一個問題。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"제가 그 제안을 받아들이면...... 대원들은 살 수 있는 겁니까?","JPN":"私がその提案を受け入れれば……隊員たちは生きられるのですね？","ENG":"If I accept your offer... will they live?","TWN":"如果我接受這個提議……那隊員們就可以活下去嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 버티는 동안이라면, 그렇네.","JPN":"君が苦痛に耐えている間は生きていられるだろう。","ENG":"As long as you can manage to hold yourself together, yes.","TWN":"只要妳能堅持住，他們就能活下去。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 고민할 필요가 없군요.","JPN":"ならば、迷う余地はありません。","ENG":"Then there's no need to hesitate any further.","TWN":"那就沒什麼好擔心了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하겠습니다.","JPN":"やらせていただきます。","ENG":"I'll do it.","TWN":"我接受。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확실한가? 한번 시술하고 나면 전으로 돌아갈 수는 없어.","JPN":"本当にいいのか？　一度施術を行えば、\\n二度と転移前には戻れないんだ。","ENG":"Are you sure? There's no going back once you've completed the procedure.","TWN":"你確定嗎？一旦進行手術，就沒辦法挽回了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지옥 같은 고통 속에서, 영원히 남을 위해 살아남겠다고?","JPN":"地獄のような苦しみの中で、永遠に他者のために生き続けると？","ENG":"Are you going to endure a living hell for eternity, just for the sake of others?","TWN":"妳願意為了拯救他人，永遠活在地獄般的痛苦中嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......오래 전에, 전 동료들을 지키겠다고 맹세하고 전대장이 됐습니다.","JPN":"……遥か昔、私は仲間たちを守ることを誓い、戦隊長になりました。","ENG":"Long ago, I swore that I would protect my colleagues when I became a Commander.","TWN":"……很久以前，我發誓要守護同伴，當上了戰隊隊長。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"피와 죽음 사이에서 싸우는 것 역시 제게는 고통이었지만......","JPN":"血しぶきと死臭漂う戦場もまた、\\n私には終わりのない苦痛でした。しかし……","ENG":"Although the bloody, deadly battles were agonizing for me...","TWN":"在血與死亡之中戰鬥，對我來說也是種痛苦……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저는, 그 날의 결정을 한 번도 후회해 본 적 없습니다.","JPN":"私は、ただの一度もあの日の誓いを悔いたことはありません。","ENG":"I've never regretted making that decision.","TWN":"但是，我從來沒有後悔過那天的決定。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니 그 때와 마찬가지로 답하겠습니다.","JPN":"ですので、あの日と同じように返答いたします。","ENG":"So I will give the same answer I did then.","TWN":"所以，我的答案和當時一樣。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"기회를 주십시오. 해내겠습니다.","JPN":"機会をお与えください。​やり遂げてみせます。","ENG":"Please give me a chance. I'll do it.","TWN":"給我一次機會吧，我會做到的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};